import redis
from typing import Dict, Any

class RedisCache:
    def __init__(self, config: Dict[str, Any]):
        self.config = config
        self.cluster_connections = {}
        for node in self.config['nodes']:
            self.connect(node)

    def connect(self, node: Dict[str, str]):
        try:
            connection = redis.Redis(host=node['host'], port=node['port'], db=node['db'])
            self.cluster_connections[node['id']] = connection
        except redis.exceptions.ConnectionError as e:
            print(f"Connection to Redis node {node['id']} failed. Error: {e}")

    def get_connection(self, node_id: str):
        try:
            return self.cluster_connections[node_id]
        except KeyError:
            print(f"No valid connection found for node {node_id}")
            return None

    def set_data(self, key: str, value: Any, ttl: int, node_id: str = None) -> bool:
        if node_id is not None and node_id in self.cluster_connections:
            try:
                connection = self.cluster_connections[node_id]
                connection.set(key, value, ex=ttl)
                return True
            except redis.exceptions.RedisError as e:
                print(f"Failed to store data. Error: {e}")
        elif node_id is None:
            for connection in self.cluster_connections.values():
                try:
                    connection.set(key, value, ex=ttl)
                    return True
                except redis.exceptions.RedisError as e:
                    print(f"Failed to store data on one of the nodes. Error: {e}")
                    continue

    def get_data(self, key: str, node_id: str = None) -> Any:
        if node_id is not None and node_id in self.cluster_connections:
            try:
                connection = self.cluster_connections[node_id]
                return connection.get(key)
            except redis.exceptions.RedisError as e:
                print(f"Failed to retrieve data. Error: {e}")
        elif node_id is None:
            for connection in self.cluster_connections.values():
                try:
                    return connection.get(key)
                except redis.exceptions.RedisError as e:
                    print(f"Failed to retrieve data on one of the nodes. Error: {e}")

